import{_ as a,o as n,c as l,a2 as e}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"Terminal Protocols","description":"Understand the foundational terminal protocols including raw mode, alternate screen, and terminal capability detection.","frontmatter":{"title":"Terminal Protocols","description":"Understand the foundational terminal protocols including raw mode, alternate screen, and terminal capability detection."},"headers":[],"relativePath":"learn/project/08-terminal-ui-with-ratatui/01-terminal-protocols.md","filePath":"learn/project/08-terminal-ui-with-ratatui/01-terminal-protocols.md"}'),o={name:"learn/project/08-terminal-ui-with-ratatui/01-terminal-protocols.md"};function t(p,s,r,c,i,y){return n(),l("div",null,[...s[0]||(s[0]=[e(`<h1 id="terminal-protocols" tabindex="-1">Terminal Protocols <a class="header-anchor" href="#terminal-protocols" aria-label="Permalink to &quot;Terminal Protocols&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How cooked mode, raw mode, and cbreak mode differ in terminal input handling</li><li>How the alternate screen buffer lets TUI apps render without destroying shell history</li><li>How to detect terminal capabilities and dimensions using crossterm</li></ul></blockquote><p>Before you can build a beautiful terminal UI, you need to understand what a terminal actually <em>is</em> and how it processes your input and output. When you type a character in your shell, it does not go directly to your program. The terminal driver -- a piece of kernel software -- intercepts it, processes it, and decides what your program sees. The mode that terminal driver operates in determines everything about how your TUI application behaves.</p><h2 id="how-terminal-input-works" tabindex="-1">How Terminal Input Works <a class="header-anchor" href="#how-terminal-input-works" aria-label="Permalink to &quot;How Terminal Input Works&quot;">​</a></h2><p>Every Unix-like system has a terminal driver (the <code>tty</code> subsystem) sitting between the keyboard and your program. This driver can operate in several modes, each offering a different level of control to your application.</p><h3 id="cooked-mode-canonical-mode" tabindex="-1">Cooked Mode (Canonical Mode) <a class="header-anchor" href="#cooked-mode-canonical-mode" aria-label="Permalink to &quot;Cooked Mode (Canonical Mode)&quot;">​</a></h3><p>This is the default mode your shell uses. In cooked mode, the terminal driver:</p><ul><li><strong>Buffers input line by line</strong> -- your program does not receive any characters until the user presses Enter.</li><li><strong>Handles line editing</strong> -- Backspace, Ctrl+W (delete word), and Ctrl+U (delete line) are processed by the driver, not your program.</li><li><strong>Interprets signals</strong> -- Ctrl+C sends SIGINT, Ctrl+Z sends SIGTSTP, Ctrl+D sends EOF.</li><li><strong>Echoes characters</strong> -- what you type appears on screen automatically.</li></ul><p>This is perfect for a simple REPL where the user types a line and presses Enter. But it is useless for a TUI. You cannot detect individual keypresses, you cannot handle arrow keys, and you cannot prevent the terminal from echoing characters you want to handle yourself.</p><h3 id="raw-mode" tabindex="-1">Raw Mode <a class="header-anchor" href="#raw-mode" aria-label="Permalink to &quot;Raw Mode&quot;">​</a></h3><p>Raw mode is the opposite extreme. The terminal driver steps aside almost completely:</p><ul><li><strong>Every keypress is delivered immediately</strong> -- no line buffering. Your program sees each character the instant it is typed.</li><li><strong>No line editing</strong> -- Backspace is just another byte (0x7F or 0x08). Your program must handle it.</li><li><strong>No signal interpretation</strong> -- Ctrl+C arrives as byte 0x03, not as a SIGINT signal. Your program decides what to do with it.</li><li><strong>No echo</strong> -- characters are not displayed unless your program explicitly writes them to the screen.</li></ul><p>This is what TUI applications need. When a user presses the up arrow key, your program receives the raw escape sequence (<code>\\x1B[A</code>) and can interpret it as &quot;scroll up&quot; or &quot;previous history item&quot; or anything else.</p><h3 id="cbreak-mode-rare-mode" tabindex="-1">Cbreak Mode (Rare Mode) <a class="header-anchor" href="#cbreak-mode-rare-mode" aria-label="Permalink to &quot;Cbreak Mode (Rare Mode)&quot;">​</a></h3><p>Cbreak mode is a middle ground: keypresses are delivered immediately (no line buffering), but signal characters like Ctrl+C still generate signals. Some applications use this, but most TUI frameworks prefer full raw mode because they want complete control over every key combination.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you would use the <code>tty</code> module to enter raw mode:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> tty</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> sys</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> termios</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">old_settings </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> termios</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">tcgetattr</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">sys</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stdin</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">try</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    tty</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">setraw</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">sys</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stdin</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">fileno</span><span style="color:#9399B2;">())</span></span>
<span class="line"><span style="color:#CDD6F4;">    ch </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> sys</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stdin</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">read</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">1</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # reads a single keypress immediately</span></span>
<span class="line"><span style="color:#CBA6F7;">finally</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CDD6F4;">    termios</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">tcsetattr</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">sys</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">stdin</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> termios</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">TCSADRAIN</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> old_settings</span><span style="color:#9399B2;">)</span></span></code></pre></div><p>The <code>curses</code> library handles this automatically with <code>curses.initscr()</code>. In Rust, the <code>crossterm</code> crate provides the same abstraction with <code>enable_raw_mode()</code> -- and it works on Windows too, which <code>tty</code>/<code>termios</code> does not.</p></div><h2 id="entering-raw-mode-with-crossterm" tabindex="-1">Entering Raw Mode with Crossterm <a class="header-anchor" href="#entering-raw-mode-with-crossterm" aria-label="Permalink to &quot;Entering Raw Mode with Crossterm&quot;">​</a></h2><p>Crossterm is the cross-platform terminal manipulation crate that Ratatui uses as its backend. Here is how you enter and exit raw mode:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> crossterm</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">terminal</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#CDD6F4;">enable_raw_mode</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> disable_raw_mode</span><span style="color:#9399B2;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#EBA0AC;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#EBA0AC;">error</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Enter raw mode -- terminal driver stops buffering and echoing</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    enable_raw_mode</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Your TUI runs here...</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Raw mode is active. Press &#39;q&#39; to quit.&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Read a single byte from stdin</span></span>
<span class="line"><span style="color:#CBA6F7;">    use</span><span style="color:#F9E2AF;"> crossterm</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">event</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Event</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> KeyCode</span><span style="color:#9399B2;">};</span></span>
<span class="line"><span style="color:#CBA6F7;">    loop</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Event</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Key</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">key_event</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;"> event</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">read</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            if</span><span style="color:#CDD6F4;"> key_event</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">code </span><span style="color:#94E2D5;">==</span><span style="color:#F9E2AF;font-style:italic;"> KeyCode</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Char</span><span style="color:#9399B2;">(</span><span style="color:#9399B2;">&#39;</span><span style="color:#A6E3A1;">q</span><span style="color:#9399B2;">&#39;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">                break</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">            }</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // ALWAYS restore the terminal before exiting</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    disable_raw_mode</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(())</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The critical rule: <strong>always restore the terminal</strong>. If your program panics or exits without calling <code>disable_raw_mode()</code>, the user&#39;s terminal is left in raw mode and becomes unusable. They will have to type <code>reset</code> blindly or close the terminal window. You will see how to handle this safely with RAII patterns in the Ratatui overview subchapter.</p><h2 id="the-alternate-screen-buffer" tabindex="-1">The Alternate Screen Buffer <a class="header-anchor" href="#the-alternate-screen-buffer" aria-label="Permalink to &quot;The Alternate Screen Buffer&quot;">​</a></h2><p>Terminals actually have two screen buffers:</p><ol><li><strong>Main screen</strong> -- where your shell history, previous commands, and output live.</li><li><strong>Alternate screen</strong> -- a completely separate drawing surface with no scroll history.</li></ol><p>When you run <code>vim</code>, <code>htop</code>, or <code>less</code>, they switch to the alternate screen. When they exit, the terminal switches back to the main screen and your shell history is exactly where you left it. This is what makes TUI apps feel like they &quot;take over&quot; the terminal without destroying anything.</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> crossterm</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">    execute</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;">    terminal</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#F9E2AF;font-style:italic;">EnterAlternateScreen</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> LeaveAlternateScreen</span><span style="color:#9399B2;">},</span></span>
<span class="line"><span style="color:#9399B2;">};</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">io</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">stdout</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#EBA0AC;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#EBA0AC;">error</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> stdout </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> stdout</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Switch to the alternate screen</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    execute!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">stdout</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> EnterAlternateScreen</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Everything you draw here is on a separate buffer.</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // The user&#39;s shell history is preserved underneath.</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Switch back to the main screen</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    execute!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">stdout</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> LeaveAlternateScreen</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Shell history is restored as if nothing happened.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(())</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>For your coding agent, the alternate screen is essential. Users expect to see their shell history when they exit the agent, not a screen full of conversation fragments.</p><h2 id="terminal-capability-detection" tabindex="-1">Terminal Capability Detection <a class="header-anchor" href="#terminal-capability-detection" aria-label="Permalink to &quot;Terminal Capability Detection&quot;">​</a></h2><p>Not all terminals are created equal. Some support 256 colors, others support true color (16 million colors), and some are limited to the basic 16 ANSI colors. Your application should detect and adapt to these capabilities.</p><h3 id="detecting-terminal-size" tabindex="-1">Detecting Terminal Size <a class="header-anchor" href="#detecting-terminal-size" aria-label="Permalink to &quot;Detecting Terminal Size&quot;">​</a></h3><p>The terminal&#39;s width and height in character cells determines your layout. Crossterm makes this straightforward:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> crossterm</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">terminal</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">size</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#EBA0AC;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#EBA0AC;">error</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">cols</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> rows</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#89B4FA;font-style:italic;"> size</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Terminal is </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> columns x </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> rows&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> cols</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> rows</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Ratatui uses this internally, but you may need it</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // for layout decisions before the TUI starts</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CDD6F4;"> cols </span><span style="color:#94E2D5;">&lt;</span><span style="color:#FAB387;"> 80</span><span style="color:#94E2D5;"> ||</span><span style="color:#CDD6F4;"> rows </span><span style="color:#94E2D5;">&lt;</span><span style="color:#FAB387;"> 24</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        eprintln!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Warning: terminal is smaller than 80x24. The UI may not display correctly.&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(())</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><h3 id="detecting-color-support" tabindex="-1">Detecting Color Support <a class="header-anchor" href="#detecting-color-support" aria-label="Permalink to &quot;Detecting Color Support&quot;">​</a></h3><p>Color detection is trickier. There is no universal standard. In practice, applications check environment variables:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> detect_color_support</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> ColorSupport</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // COLORTERM is the most reliable signal for truecolor</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ct</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;COLORTERM&quot;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> ct </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;truecolor&quot;</span><span style="color:#94E2D5;"> ||</span><span style="color:#CDD6F4;"> ct </span><span style="color:#94E2D5;">==</span><span style="color:#A6E3A1;"> &quot;24bit&quot;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#F9E2AF;font-style:italic;"> ColorSupport</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">TrueColor</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // TERM can hint at 256-color support</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">term</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;TERM&quot;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#CDD6F4;"> term</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">contains</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;256color&quot;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">            return</span><span style="color:#F9E2AF;font-style:italic;"> ColorSupport</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Color256</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    ColorSupport</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Basic16</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">enum</span><span style="color:#F9E2AF;font-style:italic;"> ColorSupport</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Basic16</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Color256</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    TrueColor</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code detects terminal capabilities at startup and adjusts its rendering accordingly. On terminals with limited color support, it falls back to a simpler color palette. OpenCode uses a similar approach, checking <code>COLORTERM</code> and <code>TERM</code> environment variables to determine whether to use its full theme or a reduced-color variant.</p></div><h2 id="the-terminal-setup-teardown-pattern" tabindex="-1">The Terminal Setup/Teardown Pattern <a class="header-anchor" href="#the-terminal-setup-teardown-pattern" aria-label="Permalink to &quot;The Terminal Setup/Teardown Pattern&quot;">​</a></h2><p>Every TUI application follows the same lifecycle:</p><ol><li><strong>Save terminal state</strong> (enter raw mode, switch to alternate screen)</li><li><strong>Run the application</strong> (event loop, rendering)</li><li><strong>Restore terminal state</strong> (leave alternate screen, disable raw mode)</li></ol><p>Step 3 must happen even if the application panics. Here is the robust pattern:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> crossterm</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">    execute</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;">    terminal</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">        enable_raw_mode</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> disable_raw_mode</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        EnterAlternateScreen</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> LeaveAlternateScreen</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">    },</span></span>
<span class="line"><span style="color:#9399B2;">};</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">io</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">stdout</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> setup_terminal</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#EBA0AC;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#EBA0AC;">error</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    enable_raw_mode</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    execute!</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">stdout</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> EnterAlternateScreen</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(())</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> restore_terminal</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#EBA0AC;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#EBA0AC;">error</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    disable_raw_mode</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    execute!</span><span style="color:#9399B2;">(</span><span style="color:#89B4FA;font-style:italic;">stdout</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> LeaveAlternateScreen</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(())</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#EBA0AC;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#EBA0AC;">error</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    setup_terminal</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Install a panic hook that restores the terminal</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> original_hook </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">panic</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">take_hook</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#F9E2AF;">    std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">panic</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">set_hook</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">Box</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#CBA6F7;">move</span><span style="color:#94E2D5;"> |</span><span style="color:#CDD6F4;">panic_info</span><span style="color:#94E2D5;">|</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> _</span><span style="color:#94E2D5;"> =</span><span style="color:#89B4FA;font-style:italic;"> restore_terminal</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        original_hook</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">panic_info</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">    }));</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Run the TUI application</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> result </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> run_app</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Normal cleanup</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    restore_terminal</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CDD6F4;">    result</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> run_app</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">(),</span><span style="color:#F9E2AF;font-style:italic;"> Box</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">dyn</span><span style="color:#EBA0AC;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#EBA0AC;">error</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Error</span><span style="color:#89DCEB;">&gt;&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Your TUI logic goes here</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(())</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The panic hook ensures that even if your code panics deep inside a widget rendering function, the terminal is restored to a usable state before the panic message prints.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li><strong>Cooked mode</strong> buffers input by line and handles editing; <strong>raw mode</strong> delivers every keypress immediately and gives your application full control -- TUI apps require raw mode.</li><li><strong>The alternate screen buffer</strong> is a separate drawing surface that preserves the user&#39;s shell history; always use it for fullscreen TUI applications.</li><li><strong>Terminal capability detection</strong> lets your application adapt its color palette and layout to the user&#39;s environment.</li><li><strong>Always restore terminal state</strong> on exit, including on panic -- the setup/teardown pattern with a panic hook is the standard approach.</li><li><strong>Crossterm</strong> provides cross-platform abstractions for raw mode, alternate screen, terminal size detection, and event reading that work on macOS, Linux, and Windows.</li></ul>`,43)])])}const B=a(o,[["render",t]]);export{u as __pageData,B as default};
